import { useState, useEffect } from 'react';

import { ToggleButtonGroup } from '@mui/material';

import { useSprintConfiguration } from '../../contexts/sprint-configuration';
import { FieldLabel, ToggleButton } from '../../components';

export function Units() {
	console.log( 'Units' );

	const {
		sprintConfig,
		setUnits,
	} = useSprintConfiguration();

	const [ selectedUnits, setSelectedUnits ] = useState( () => sprintConfig.units );

	useEffect( () => {
		setUnits( selectedUnits );
	}, [ selectedUnits, setUnits ] );

	return (
		<>
			<FieldLabel>Units:</FieldLabel>
			<ToggleButtonGroup
				value={ selectedUnits }
				onChange={ ( _, value ) => value && setSelectedUnits( value ) }
				exclusive
				color="primary"
				size="small"
				fullWidth
			>
				<ToggleButton value="man-days">Man Days</ToggleButton>
				<ToggleButton value="story-points">Story Points</ToggleButton>
			</ToggleButtonGroup>
		</>
	);
}
