import { ToggleButton as MuiToggleButton } from '@mui/material';

const sx = {
	fontSize: {
		xs: '0.7rem',
		sm: '0.85rem',
	},
};

export function ToggleButton( { children, sx: sxOverrides, ...props } ) {
	return (
		<MuiToggleButton
			variant="dark"

			sx={ {
				...sx,
				...sxOverrides,
			} }

			{ ...props }
		>
			{ children }
		</MuiToggleButton>
	);
}
