import { Stack, IconButton } from '@mui/material';

import {
	ArrowBack as PreviousSprint,
	ArrowForward as NextSprint,
} from '@mui/icons-material';

import { DatePicker } from '../../components';

import { formatDate } from '../../utils/date';
import { useSprintConfiguration } from '../../contexts/sprint-configuration';

export function SprintNavigation() {
	console.log( 'Sprint Navigation' );

	const {
		sprintConfig,
		setStartDate,
	} = useSprintConfiguration();

	const nextSprint = () => {
		const newDate = new Date( sprintConfig.startDate );
		newDate.setDate( newDate.getDate() + sprintConfig.duration );
		setStartDate( formatDate( newDate ) );
	};

	const previousSprint = () => {
		const newDate = new Date( sprintConfig.startDate );
		newDate.setDate( newDate.getDate() - sprintConfig.duration );
		setStartDate( formatDate( newDate ) );
	};

	return (
		<Stack flexDirection="row" gap={ 1.25 }>
			<IconButton onClick={ () => previousSprint() }>
				<PreviousSprint />
			</IconButton>
			<DatePicker
				value={ sprintConfig.startDate }
				onChange={ setStartDate }
			/>
			<IconButton onClick={ () => nextSprint() }>
				<NextSprint />
			</IconButton>
		</Stack>
	);
}
