import { useState, useEffect } from 'react';

import { readJson, writeJson } from '../utils/local-storage';

export function useLocalStorage( key, initialValue = '' ) {
	const [ storedValue, updateValue ] = useState( () => {
		return readJson( key, initialValue );
	} );

	useEffect( () => {
		writeJson( key, storedValue );
	}, [ storedValue, key ] );

	return [ storedValue, updateValue ];
}
