import { DatePicker as MuiDatePicker } from '@mui/x-date-pickers';
import dayjs from 'dayjs';

export function DatePicker( { value: date, onChange } ) {
	const selectedDate = Boolean( date)
		? dayjs( date, 'YYYY-MM-DD', true )
		: dayjs();

	return (
		<MuiDatePicker
			format="LL"
			value={ selectedDate }
			onChange={ ( newDate ) => onChange( newDate.format( 'YYYY-MM-DD' ) ) }
			slotProps={ {
				textField: {
					readOnly: true,
					size: 'small',
				},
			} }
		/>
	);
}
