import { useState } from 'react';

import {
	IconButton,
	MenuItem,
	Divider,
	Typography,
} from '@mui/material';

import { Menu } from '../components';
import { SCP } from '../constants';

import {
	MoreVert as MenuIcon,
	CloudDownloadOutlined as DownloadIcon,
	CloudUploadOutlined as UploadIcon,
} from '@mui/icons-material';

export function MainMenu() {
	const [ anchorEl, setAnchorEl ] = useState( null );

	const closeMenu = () => {
		setAnchorEl( null );
	};

	const handleExport = () => {
		window.dispatchEvent( new CustomEvent( SCP.events.storage.export ) );
		closeMenu();
	};

	const handleImport = () => {
		window.dispatchEvent( new CustomEvent( SCP.events.storage.import ) );
		closeMenu();
	};

	return (
		<>
			<IconButton onClick={ ( e ) => { setAnchorEl( e.currentTarget); } }>
				<MenuIcon sx={ ( theme ) => ( {
					color: theme.palette.primary.text,
				} ) } />
			</IconButton>

			{ anchorEl && (
				<Menu
					anchorEl={ anchorEl }
        			anchorOrigin={ { horizontal: 'right', vertical: 'bottom' } }
					transformOrigin={ { horizontal: 'right', vertical: 'top' } }

					open
					onClose={ closeMenu }
				>
					<MenuItem dense onClick={ handleExport }>
						<MenuItemLabel
							icon={ DownloadIcon }
							text="Export"
							suffix=".json"
						/>
					</MenuItem>

					<Divider />

					<MenuItem disabled dense onClick={ handleImport }>
						<MenuItemLabel
							icon={ UploadIcon }
							text="Import"
							suffix=".json"
						/>
					</MenuItem>
				</Menu>
			) }
		</>
	);
}

function MenuItemLabel( props = { text: '' } ) {
	const {
		icon: Icon,
		text,
		suffix,
	} = props;

	return (
		<>
			{ Icon && <Icon sx={ { mr: 1 } } /> }
			{text}
			{ suffix && <Suffix>.json</Suffix> }
		</>
	);
}

function Suffix( { children } ) {
	return (
		<Typography
			variant="body2"
			component="span"
			sx={ { color: '#808080' } }
		>
			&nbsp; ( { children } )
		</Typography>
	);
}
