import { useState, useEffect } from 'react';

import { FieldLabel, Slider } from '../../components';
import { useSprintConfiguration } from '../../contexts/sprint-configuration';

export function Buffer() {
	console.log( 'Buffer' );

	const {
		sprintConfig,
		setBuffer,
	} = useSprintConfiguration();

	const [ slackBuffer, setSlackBuffer ] = useState( () => sprintConfig.buffer );

	useEffect( () => {
		setBuffer( slackBuffer )
	}, [ slackBuffer, setBuffer ] );

	const bufferValue = ( 0 < slackBuffer )
		? ` ${ slackBuffer }%`
		: '';

	return (
		<>
			<FieldLabel>Buffer{ bufferValue }:</FieldLabel>
			<Slider
				size="medium"
				value={ slackBuffer }
				onChange={ ( _, value ) => setSlackBuffer( value ) }
				step={ 5 }
				max={ 75 }
				marks={ [
					{ value: 0, label: '0%' },
					{ value: 15, label: '15%' },
					{ value: 30, label: '30%' },
					{ value: 45, label: '45%' },
					{ value: 60, label: '60%' },
					{ value: 75, label: '75%' },
				] }
				valueLabelDisplay="auto"
			/>
		</>
	);
}
