import { useEffect, useState } from 'react';

import {
	Dialog,
	DialogTitle,
	DialogActions,
	DialogContent,

	Button,
} from '@mui/material';

import { CloseIconButton, SubmitButton } from '../components';

import { SCP } from '../constants';

export function ImportJson() {
	console.log( 'ImportJson' );

	const [ open, setOpen ] = useState( false );
	const [ fileName, setFileName ] = useState( '' );

	const openDialog = () => {
		setOpen( true );
	};

	const closeDialog = () => {
		setOpen( false );
	};

	useEffect( () => {
		window.addEventListener( SCP.events.storage.import, openDialog );
		return () => {
			window.removeEventListener( SCP.events.storage.import, openDialog );
		};
	}, [] );

	const handleSubmit = ( e ) => {
		e.preventDefault();
		e.stopPropagation();

		closeDialog();
	}

	return (
		<>
			{ open && (
				<Dialog
					open={ open }
					onClose={ closeDialog }

					fullWidth
					maxWidth="sm"

					sx={ ( theme ) => ( {
						zIndex: theme.scp.zIndex.dialog,
					} ) }
				>
					<DialogTitle>Import</DialogTitle>
					<CloseIconButton onClick={ closeDialog } />

					<DialogContent dividers>
						<p>Hello, you're about to import the file!</p>
						<form id="scp-import-form" onSubmit={ handleSubmit} ></form>
					</DialogContent>

					<DialogActions>
						<Button type="button" onClick={ closeDialog }>Cancel</Button>
						<SubmitButton form="scp-import-form">Import</SubmitButton>
					</DialogActions>
				</Dialog>
			) }
		</>
	);
}