import { createContext, useContext, useCallback } from 'react';
import { generateId } from '../utils/generate-id';
import { useLocalStorage } from '../hooks/use-local-storage';

import { SCP } from '../constants';

const TeamMembersCtx = createContext(undefined);

export function useTeamMembers() {
	const ctx = useContext(TeamMembersCtx);
	if ( ! ctx ) {
		throw new Error('useTeamMembers hook must be used within TeamMembersContext');
	}
	return ctx;
}

export function TeamMembersContext( { children } ) {
	const [ teamMembers, setTeamMembers ] = useLocalStorage( SCP.storage.teamMembers, [] );

	const addTeamMember = useCallback( ( name, schedule, status = 'active' ) => {
		const newMember = {
			id: generateId( 'scp-tm' ),
			name: name,
			schedule: schedule,
			status: status,
		};

		setTeamMembers( ( all ) => {
			return [
				...all,
				newMember,
			];
		} );
	}, [ setTeamMembers ] );

	const removeTeamMember = useCallback( ( id ) => {
		setTeamMembers( ( all ) => {
			return all.filter( ( teamMember ) => {
				return teamMember.id !== id;
			} );
		} );
	}, [ setTeamMembers ] );

	const updateTeamMember = useCallback( ( id, updates = {} ) => {
		setTeamMembers( ( all ) => {
			const idx = all.findIndex( ( item ) => {
				return item.id === id;
			} );

			const member = all[ idx ];

			all[ idx ] = {
				...member,
				...updates,
			};

			return [ ...all ];
		} );
	}, [ setTeamMembers ] );

	const toggleStatus = useCallback( ( id ) => {
		const teamMember = teamMembers.find( ( member ) => member.id === id );
		updateTeamMember( id, {
			status: 'active' === teamMember.status ? 'inactive' : 'active',
		} );
	}, [ teamMembers, updateTeamMember ] );

	const updateWorkSchedule = useCallback( ( id, schedule ) => {
		updateTeamMember( id, {
			schedule: schedule,
		} );
	}, [ updateTeamMember ] );

	const context = {
		teamMembers,
		addTeamMember,
		removeTeamMember,
		toggleStatus,
		updateWorkSchedule,
	};

	return (
		<TeamMembersCtx.Provider value={ context }>
			{ children }
		</TeamMembersCtx.Provider>
	);
}
